+static inline void emit_fp_ucom(MacroAssembler* masm, enum FP_PREC pt,
+                                XMMRegister p, XMMRegister q) {
+  if (pt == fp_prec_hlf) {
+    if (VM_Version::supports_avx10_2()) {
+      __ vucomxsh(p, q);
+    } else {
+      __ vucomish(p, q);
+    }
+  } else if (pt == fp_prec_flt) {
+    if (VM_Version::supports_avx10_2()) {
+      __ vucomxss(p, q);
+    } else {
+      __ ucomiss(p, q);
+    }
+  } else {
+    if (VM_Version::supports_avx10_2()) {
+      __ vucomxsd(p, q);
+    } else {
+      __ ucomisd(p, q);
+    }
+  }
+}
